#include <bits/stdc++.h>
using namespace std;
int t,n;
int a[4];
vector<pair<int,int>> v[4];
void slove() {
	cin>>n;
	int sum=0;
	for(int i=1; i<=3; i++) {
		v[i].clear();
	}
	for(int i=1; i<=n; i++) {
		cin>>a[1]>>a[2]>>a[3];
		int Max=max({a[1],a[2],a[3]});
		sum+=Max;
		int sub;
		if(Max==a[1]) {
			if(a[2]>a[3]) {
				sub=a[1]-a[2];
			} else {
				sub=a[1]-a[3];
			}
			v[1].push_back({sub,Max});
		} else if(Max==a[2]) {
			if(a[1]>a[3]) {
				sub=a[2]-a[1];
			} else {
				sub=a[2]-a[3];
			}
			v[2].push_back({sub,Max});
		} else {
			if(a[1]>a[2]) {
				sub=a[3]-a[1];
			} else {
				sub=a[3]-a[2];
			}
			v[3].push_back({sub,Max});
		}
	}
	if(v[1].size()<=n/2&&v[2].size()<=n/2&&v[3].size()<=n/2) {
		cout<<sum<<"\n";
		return ;
	}
	for(int i=1; i<=3; i++) {
		if(v[i].size()>n/2) {
			sort(v[i].begin(),v[i].end());
			int k=v[i].size()-n/2;
			for(int j=0; j<k; j++) {
				sum-=v[i][j].first;
			}
		}
	}
	cout<<sum<<"\n";
}
int main() {
	ios::sync_with_stdio(0),cin.tie(0),cout.tie(0);
	cin>>t;
	while(t--) {
		slove();
	}
	return 0;
}
